// Flatten PRs from nested GitHub response
const prs = [];
for (const item of $input.all()) {
  if (item.json.results && Array.isArray(item.json.results)) {
    for (const pr of item.json.results) {
      prs.push({
        repository: item.json.owner || item.json.repository,
        pr_number: pr.number,
        pr_title: pr.title,
        pr_url: pr.html_url,
        author: pr.user?.login,
        author_avatar: pr.user?.avatar_url,
        state: pr.state,
        created_at: pr.created_at,
        updated_at: pr.updated_at,
        additions: pr.additions,
        deletions: pr.deletions,
        changed_files: pr.changed_files,
        labels: pr.labels?.map(l => l.name) || [],
        draft: pr.draft,
        mergeable: pr.mergeable,
        reviews_requested: pr.requested_reviewers?.length || 0
      });
    }
  }
}
return { items: prs };

// Flatten releases from nested GitHub response
const releases = [];
for (const item of $input.all()) {
  if (item.json.results && Array.isArray(item.json.results)) {
    for (const release of item.json.results) {
      releases.push({
        repository: item.json.owner || item.json.repository,
        version: release.tag_name,
        name: release.name,
        url: release.html_url,
        author: release.author?.login,
        published_at: release.published_at,
        created_at: release.created_at,
        is_draft: release.draft,
        is_prerelease: release.prerelease,
        body: release.body,
        assets_count: release.assets?.length || 0
      });
    }
  }
}
return { items: releases };

// Build consolidated ALDECI findings payload
const timestamp = new Date().toISOString();
const org = process.env.GITHUB_ORG_NAME || 'unknown-org';

const findings = [];

// Create findings from metadata
for (const repo of $input.all()) {
  findings.push({
    finding_type: 'repository_metadata',
    entity_type: 'repository',
    entity_id: repo.json.full_name,
    severity: 'info',
    source: 'github',
    scanner: 'github-repo-scanner',
    discovery_time: timestamp,
    data: {
      organization: org,
      repository_name: repo.json.repository_name,
      full_name: repo.json.full_name,
      url: repo.json.url,
      description: repo.json.description,
      language: repo.json.language,
      topics: repo.json.topics,
      stars: repo.json.stars,
      watchers: repo.json.watchers,
      forks: repo.json.forks,
      open_issues: repo.json.open_issues,
      is_private: repo.json.is_private,
      is_fork: repo.json.is_fork,
      last_activity_days_ago: repo.json.last_activity_days_ago,
      license: repo.json.license
    }
  });

  // Flag inactive repositories
  if (repo.json.last_activity_days_ago > 180) {
    findings.push({
      finding_type: 'inactive_repository',
      entity_type: 'repository',
      entity_id: repo.json.full_name,
      severity: 'medium',
      title: `Repository ${repo.json.repository_name} inactive for ${repo.json.last_activity_days_ago} days`,
      source: 'github',
      scanner: 'github-repo-scanner',
      discovery_time: timestamp,
      data: {
        last_pushed: repo.json.pushed_at,
        days_inactive: repo.json.last_activity_days_ago
      }
    });
  }
}

return { items: findings };
